1	/**
2	 * Zone Zero interactive simulator.
3	 * Extracted from monolith index.html (lines 4784-5254).
4	 *
5	 * 4-slider MIND dimension controls with live particle visualization,
6	 * geometric mean scoring, collapse detection, and social sharing.
7	 */
8	
9	import * as THREE from 'three';
10	import gsap from 'gsap';
11	import { getDeviceCapability } from './device-detect';
12	import { trackEvent } from './analytics';
13	
14	/* -- Types -- */
15	interface ZoneZeroState {
16	  scores: Record<'m' | 'i' | 'n' | 'd', number>;
17	  isCollapsed: boolean;
18	}
19	
20	interface HealthState {
21	  min: number;
22	  badge: string;
23	  name: string;
24	  insight: string;
25	}
26	
27	/* -- Score calculation -- */
28	function calcScore(vals: Record<'m' | 'i' | 'n' | 'd', number>): number {
29	  const { m, i, n, d } = vals;
30	  if (m <= 0 || i <= 0 || n <= 0 || d <= 0) return 0;
31	  return Math.round(Math.pow((m / 100) * (i / 100) * (n / 100) * (d / 100), 0.25) * 100);
32	}
33	
34	export function initZoneZero(container: HTMLElement): void {
35	  const device = getDeviceCapability();
36	
37	  const ZZ_COUNTS = { full: 1800, reduced: 800, minimal: 0 } as const;
38	  const zzParticleCount = ZZ_COUNTS[device.tier];
39	  if (zzParticleCount === 0) return; // minimal tier — CSS fallback
40	
41	  const canvas = document.getElementById('zz-canvas') as HTMLCanvasElement | null;
42	  if (!canvas) return;
43	
44	  // -- Slider refs --
45	  const sliders: Record<'m' | 'i' | 'n' | 'd', HTMLInputElement> = {
46	    m: document.getElementById('zz-m') as HTMLInputElement,
47	    i: document.getElementById('zz-i') as HTMLInputElement,
48	    n: document.getElementById('zz-n') as HTMLInputElement,
49	    d: document.getElementById('zz-d') as HTMLInputElement,
50	  };
51	  const valEls: Record<'m' | 'i' | 'n' | 'd', HTMLElement> = {
52	    m: document.getElementById('zz-m-val')!,
53	    i: document.getElementById('zz-i-val')!,
54	    n: document.getElementById('zz-n-val')!,
55	    d: document.getElementById('zz-d-val')!,
56	  };
57	  const warnEls: Record<'m' | 'i' | 'n' | 'd', HTMLElement> = {
58	    m: document.getElementById('zz-m-warn')!,
59	    i: document.getElementById('zz-i-warn')!,
60	    n: document.getElementById('zz-n-warn')!,
61	    d: document.getElementById('zz-d-warn')!,
62	  };
63	  const scoreEl = document.getElementById('zz-score-num')!;
64	  const badgeEl = document.getElementById('zz-health-badge')!;
65	  const nameEl = document.getElementById('zz-health-name')!;
66	  const insightEl = document.getElementById('zz-health-insight')!;
67	  const constraintT = document.getElementById('zz-constraint-title')!;
68	  const constraintTx = document.getElementById('zz-constraint-text')!;
69	  const overlay = document.getElementById('zz-collapse-overlay')!;
70	  const overlayDim = document.getElementById('zz-collapse-dim')!;
71	  const overlayRsn = document.getElementById('zz-collapse-reason')!;
72	  const resetBtn = document.getElementById('zz-reset')!;
73	
74	  const FLOOR = 15; // below this triggers collapse state
75	  const DEFAULTS: Record<'m' | 'i' | 'n' | 'd', number> = { m: 70, i: 60, n: 50, d: 40 };
76	  const COLORS: Record<'m' | 'i' | 'n' | 'd', string> = {
77	    m: '#00ff88',
78	    i: '#00c8ff',
79	    n: '#7b4bff',
80	    d: '#ffb400',
81	  };
82	  const NAMES: Record<'m' | 'i' | 'n' | 'd', string> = {
83	    m: 'Material',
84	    i: 'Intelligence',
85	    n: 'Network',
86	    d: 'Diversity',
87	  };
88	
89	  // Keep COLORS accessible for potential future use
90	  void COLORS;
91	
92	  // -- Three.js setup --
93	  const wrap = canvas.parentElement!;
94	  const W = (): number => wrap.clientWidth;
95	  const H = (): number => wrap.clientHeight;
96	
97	  const renderer = new THREE.WebGLRenderer({ canvas, antialias: device.tier === 'full', alpha: true });
98	  renderer.setPixelRatio(device.pixelRatioLimit);
99	  renderer.setSize(W(), H());
100	  renderer.setClearColor(0x020204, 1);
101	
102	  const scene = new THREE.Scene();
103	  const camera = new THREE.PerspectiveCamera(60, W() / H(), 0.1, 500);
104	  camera.position.z = 110;
105	
106	  // -- Particle system --
107	  const N = zzParticleCount;
108	  const positions = new Float32Array(N * 3);
109	  const colors_arr = new Float32Array(N * 3);
110	  const targets = new Float32Array(N * 3); // orbit targets
111	  const velocities = new Float32Array(N * 3); // scatter velocities
112	  const phases = new Float32Array(N); // per-particle phase offset
113	
114	  // Seeded RNG for deterministic layout
115	  const rng = (s: number): number => {
116	    const x = Math.sin(s * 9301 + 49297) * 233280;
117	    return x - Math.floor(x);
118	  };
119	
120	  // Build cluster targets: 4 clusters (one per dimension) + scattered noise
121	  const clusterCentres: number[][] = [
122	    [-28, 18, 0], // M -- top-left
123	    [28, 18, 0], // I -- top-right
124	    [-28, -18, 0], // N -- bottom-left
125	    [28, -18, 0], // D -- bottom-right
126	  ];
127	  const clusterColors: number[][] = [
128	    [0, 1, 0.53], // #00ff88
129	    [0, 0.78, 1], // #00c8ff
130	    [0.48, 0.29, 1], // #7b4bff
131	    [1, 0.71, 0], // #ffb400
132	  ];
133	
134	  for (let i = 0; i < N; i++) {
135	    const ci = i % 4; // which cluster
136	    const cx = clusterCentres[ci];
137	    const frac = rng(i * 3);
138	    const r = frac < 0.7 ? rng(i * 7 + 1) * 22 : rng(i * 13 + 2) * 55;
139	    const th = rng(i * 5 + 3) * Math.PI * 2;
140	    const phi = rng(i * 11 + 4) * Math.PI;
141	    const x = cx[0] + r * Math.sin(phi) * Math.cos(th);
142	    const y = cx[1] + r * Math.sin(phi) * Math.sin(th);
143	    const z = cx[2] + r * Math.cos(phi) * 0.3;
144	    targets[i * 3] = x;
145	    targets[i * 3 + 1] = y;
146	    targets[i * 3 + 2] = z;
147	    positions[i * 3] = (rng(i * 17 + 5) - 0.5) * 160;
148	    positions[i * 3 + 1] = (rng(i * 19 + 6) - 0.5) * 160;
149	    positions[i * 3 + 2] = (rng(i * 23 + 7) - 0.5) * 60;
150	    colors_arr[i * 3] = clusterColors[ci][0];
151	    colors_arr[i * 3 + 1] = clusterColors[ci][1];
152	    colors_arr[i * 3 + 2] = clusterColors[ci][2];
153	    velocities[i * 3] = (rng(i * 29 + 8) - 0.5) * 0.8;
154	    velocities[i * 3 + 1] = (rng(i * 31 + 9) - 0.5) * 0.8;
155	    velocities[i * 3 + 2] = (rng(i * 37 + 10) - 0.5) * 0.4;
156	    phases[i] = rng(i * 41 + 11) * Math.PI * 2;
157	  }
158	
159	  const geo = new THREE.BufferGeometry();
160	  geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
161	  geo.setAttribute('color', new THREE.BufferAttribute(colors_arr, 3));
162	
163	  const mat = new THREE.PointsMaterial({
164	    size: 1.8,
165	    vertexColors: true,
166	    transparent: true,
167	    opacity: 0.85,
168	    sizeAttenuation: true,
169	  });
170	
171	  const points = new THREE.Points(geo, mat);
172	  scene.add(points);
173	
174	  // -- State --
175	  const scoreProxy = { val: 0 }; // animated score number
176	  let mindScore = 52;
177	  const dimScores: Record<'m' | 'i' | 'n' | 'd', number> = { m: 70, i: 60, n: 50, d: 40 };
178	  let isCollapsed = false;
179	
180	  // Keep state interface accessible for type checking
181	  void ({} as ZoneZeroState);
182	
183	  // -- UI state updates --
184	  const HEALTH: HealthState[] = [
185	    {
186	      min: 70,
187	      badge: 'thriving',
188	      name: 'Symbiotic Zone',
189	      insight:
190	        'All four capitals are mutually reinforcing. This city is a candidate for nucleation — a proof-of-concept others will imitate.',
191	    },
192	    {
193	      min: 50,
194	      badge: 'thriving',
195	      name: 'Healthy System',
196	      insight:
197	        'The city is above the stability threshold. Further investment in the binding constraint will compound across all other capitals.',
198	    },
199	    {
200	      min: 35,
201	      badge: 'stressed',
202	      name: 'Under Stress',
203	      insight:
204	        'One or more capitals are lagging. The multiplicative penalty is already visible — a 10-point gap here costs more than 10 points in the total score.',
205	    },
206	    {
207	      min: 20,
208	      badge: 'critical',
209	      name: 'Critical Threshold',
210	      insight:
211	        'The system is near the collapse floor. At this level, capitals begin to degrade each other. Intervention is urgent.',
212	    },
213	    {
214	      min: 1,
215	      badge: 'critical',
216	      name: 'Pre-Collapse',
217	      insight:
218	        'Any further decline in the binding constraint will trigger systemic cascade. The multiplicative model shows no mercy at this range.',
219	    },
220	    {
221	      min: 0,
222	      badge: 'collapsed',
223	      name: 'Systemic Collapse',
224	      insight:
225	        'A single dimension at zero pulls the entire product to zero. This is why GDP — which adds rather than multiplies — masks these failures entirely.',
226	    },
227	  ];
228	
229	  const DIM_INSIGHTS: Record<'m' | 'i' | 'n' | 'd', (v: number) => string> = {
230	    m: (v) =>
231	      `Material (${v}) is the binding constraint. Physical infrastructure is the substrate everything else runs on — raise it first.`,
232	    i: (v) =>
233	      `Intelligence (${v}) is the binding constraint. Without open knowledge infrastructure, the other capitals cannot compound.`,
234	    n: (v) =>
235	      `Network (${v}) is the binding constraint. Isolated nodes cannot multiply. Cooperative density is the transmission mechanism.`,
236	    d: (v) =>
237	      `Diversity (${v}) is the binding constraint. Monocultures are fragile. Variety is the system's immune response to shocks.`,
238	  };
239	
240	  function updateUI(vals: Record<'m' | 'i' | 'n' | 'd', number>): void {
241	    const score = calcScore(vals);
242	    mindScore = score;
243	    const keys: ('m' | 'i' | 'n' | 'd')[] = ['m', 'i', 'n', 'd'];
244	
245	    // Collapsed?
246	    const collapsedDim = keys.find((k) => vals[k] <= 0);
247	    const floorDims = keys.filter((k) => vals[k] > 0 && vals[k] <= FLOOR);
248	    isCollapsed = !!collapsedDim;
249	
250	    // Suppress unused variable warning
251	    void floorDims;
252	
253	    overlay.classList.toggle('visible', isCollapsed);
254	    if (isCollapsed && collapsedDim) {
255	      overlayDim.textContent = `${NAMES[collapsedDim]} at Zero`;
256	      overlayRsn.textContent = `${NAMES[collapsedDim]} Capital collapsed. In a multiplicative system, one zero destroys the product of all other capitals. M \u00D7 I \u00D7 N \u00D7 0 = 0, always.`;
257	    }
258	
259	    // Score number -- tween
260	    gsap.to(scoreProxy, {
261	      val: score,
262	      duration: 0.5,
263	      ease: 'power2.out',
264	      onUpdate() {
265	        scoreEl.textContent = String(Math.round(scoreProxy.val));
266	      },
267	      onComplete() {
268	        scoreEl.textContent = String(score);
269	      },
270	    });
271	
272	    // Score colour class
273	    scoreEl.classList.remove('stressed', 'collapsing');
274	    if (score < 35) scoreEl.classList.add('collapsing');
275	    else if (score < 55) scoreEl.classList.add('stressed');
276	
277	    // Health state
278	    const state = HEALTH.find((h) => score >= h.min) || HEALTH[HEALTH.length - 1];
279	    badgeEl.className = `zz-health-badge ${state.badge}`;
280	    badgeEl.textContent = state.badge.charAt(0).toUpperCase() + state.badge.slice(1);
281	    nameEl.textContent = state.name;
282	    insightEl.textContent = state.insight;
283	
284	    // Binding constraint
285	    if (!isCollapsed) {
286	      const minKey = keys.reduce((a, b) => (vals[a] < vals[b] ? a : b));
287	      constraintT.textContent = 'Binding Constraint';
288	      constraintTx.textContent = DIM_INSIGHTS[minKey](vals[minKey]);
289	    } else {
290	      constraintT.textContent = 'System Status';
291	      constraintTx.textContent =
292	        'Restore any zero-floor dimension above 0 to restart the ecosystem.';
293	    }
294	
295	    // Per-slider warnings and fill gradient
296	    keys.forEach((k) => {
297	      const v = vals[k];
298	      const pct = v + '%';
299	      sliders[k].style.setProperty('--pct', pct);
300	      valEls[k].textContent = String(v);
301	      valEls[k].classList.toggle('floor', v <= FLOOR);
302	      warnEls[k].classList.toggle('visible', v <= FLOOR && v > 0);
303	    });
304	  }
305	
306	  // -- Particle animation --
307	  let t = 0;
308	  const dimKeys: ('m' | 'i' | 'n' | 'd')[] = ['m', 'i', 'n', 'd'];
309	  const scatterAccum = new Float32Array(N * 3); // accumulated scatter offset
310	  let zzVisible = true;
311	  let zzAnimRunning = false;
312	
313	  // Pause render loop when zone-zero section is off-screen (PERF-05)
314	  const zzSection = container.closest('section') || container;
315	  const zzRenderObserver = new IntersectionObserver(
316	    (entries) => {
317	      zzVisible = entries[0].isIntersecting;
318	      if (zzVisible && !zzAnimRunning) startZZLoop();
319	    },
320	    { threshold: 0 },
321	  );
322	  zzRenderObserver.observe(zzSection);
323	
324	  function animate(): void {
325	    if (!zzVisible) {
326	      zzAnimRunning = false;
327	      return;
328	    }
329	    requestAnimationFrame(animate);
330	    zzAnimRunning = true;
331	    t += 0.012;
332	
333	    const pos = geo.attributes.position.array as Float32Array;
334	    const vals = dimScores;
335	
336	    // Per-cluster cohesion
337	    const coh = dimKeys.map((k) => Math.max(0, vals[k] / 100));
338	    const globalCoh = calcScore(vals) / 100;
339	
340	    for (let i = 0; i < N; i++) {
341	      const ci = i % 4;
342	      const c = coh[ci];
343	      const ph = phases[i];
344	      const cx = clusterCentres[ci];
345	
346	      // Orbit: gentle elliptical drift around cluster centre
347	      const orbitR = 8 * (1 - c * 0.6); // tighter at high cohesion
348	      const orbitTh = t * (0.2 + 0.1 * rng(i)) + ph;
349	      const orbitX = cx[0] + targets[i * 3] * c + orbitR * Math.cos(orbitTh) * (1 - c);
350	      const orbitY = cx[1] + targets[i * 3 + 1] * c + orbitR * Math.sin(orbitTh) * (1 - c);
351	      const orbitZ = cx[2] + targets[i * 3 + 2] * c * 0.4;
352	
353	      // Scatter: grows as cohesion drops
354	      const scatter = 1 - c;
355	      scatterAccum[i * 3] += velocities[i * 3] * scatter * 0.05;
356	      scatterAccum[i * 3 + 1] += velocities[i * 3 + 1] * scatter * 0.05;
357	      scatterAccum[i * 3 + 2] += velocities[i * 3 + 2] * scatter * 0.02;
358	
359	      // When cohesion recovers, damp the scatter back
360	      if (c > 0.5) {
361	        scatterAccum[i * 3] *= 0.94;
362	        scatterAccum[i * 3 + 1] *= 0.94;
363	        scatterAccum[i * 3 + 2] *= 0.94;
364	      }
365	
366	      // Clamp scatter so particles don't fly off to infinity
367	      const sx = Math.max(-80, Math.min(80, scatterAccum[i * 3]));
368	      const sy = Math.max(-60, Math.min(60, scatterAccum[i * 3 + 1]));
369	      const sz = Math.max(-30, Math.min(30, scatterAccum[i * 3 + 2]));
370	      scatterAccum[i * 3] = sx;
371	      scatterAccum[i * 3 + 1] = sy;
372	      scatterAccum[i * 3 + 2] = sz;
373	
374	      pos[i * 3] = orbitX + sx;
375	      pos[i * 3 + 1] = orbitY + sy;
376	      pos[i * 3 + 2] = orbitZ + sz;
377	    }
378	
379	    geo.attributes.position.needsUpdate = true;
380	
381	    // Global particle size + opacity follows overall health
382	    mat.size = 0.6 + globalCoh * 1.8;
383	    mat.opacity = 0.3 + globalCoh * 0.65;
384	
385	    // Slow camera drift for life
386	    camera.position.x = Math.sin(t * 0.08) * 4;
387	    camera.position.y = Math.cos(t * 0.06) * 2;
388	
389	    renderer.render(scene, camera);
390	  }
391	
392	  function startZZLoop(): void {
393	    if (!zzAnimRunning) {
394	      zzAnimRunning = true;
395	      animate();
396	    }
397	  }
398	
399	  startZZLoop();
400	
401	  // CONV-09: Track when simulator scrolls into viewport (separate from render-pause observer)
402	  const analyticsSection = document.getElementById('zone-zero');
403	  if (analyticsSection) {
404	    const analyticsObserver = new IntersectionObserver((entries) => {
405	      entries.forEach((entry) => {
406	        if (entry.isIntersecting) {
407	          trackEvent('Simulator Opened');
408	          analyticsObserver.disconnect(); // Fire only once
409	        }
410	      });
411	    }, { threshold: 0.2 });
412	    analyticsObserver.observe(analyticsSection);
413	  }
414	
415	  // Suppress unused variable warning for mindScore / isCollapsed
416	  void mindScore;
417	  void isCollapsed;
418	
419	  // -- Resize --
420	  const ro = new ResizeObserver(() => {
421	    renderer.setSize(W(), H());
422	    camera.aspect = W() / H();
423	    camera.updateProjectionMatrix();
424	  });
425	  ro.observe(wrap);
426	
427	  // -- Slider events --
428	  let sliderInteracted = false;
429	  (['m', 'i', 'n', 'd'] as const).forEach((k) => {
430	    sliders[k].addEventListener('input', () => {
431	      dimScores[k] = parseInt(sliders[k].value, 10);
432	      updateUI(dimScores);
433	      // CONV-09: Track first slider interaction
434	      if (!sliderInteracted) {
435	        sliderInteracted = true;
436	        trackEvent('Simulator Interacted');
437	      }
438	    });
439	  });
440	
441	  // -- Reset --
442	  resetBtn.addEventListener('click', () => {
443	    Object.assign(dimScores, DEFAULTS);
444	    (['m', 'i', 'n', 'd'] as const).forEach((k) => {
445	      sliders[k].value = String(DEFAULTS[k]);
446	    });
447	    updateUI(dimScores);
448	    // Clear params from URL without reload
449	    history.replaceState(null, '', window.location.pathname + window.location.hash);
450	    document.getElementById('zz-shared-banner')?.classList.remove('visible');
451	  });
452	
453	  // -- URL param hydration (load shared config) --
454	  (function hydrateFromURL(): void {
455	    const params = new URLSearchParams(window.location.search);
456	    const keys: ('m' | 'i' | 'n' | 'd')[] = ['m', 'i', 'n', 'd'];
457	    let hasAny = false;
458	    keys.forEach((k) => {
459	      if (params.has(k)) {
460	        const v = Math.max(0, Math.min(100, parseInt(params.get(k)!, 10) || 0));
461	        dimScores[k] = v;
462	        sliders[k].value = String(v);
463	        hasAny = true;
464	      }
465	    });
466	    if (hasAny) {
467	      // Show the shared-config banner and scroll section into view after a tick
468	      document.getElementById('zz-shared-banner')?.classList.add('visible');
469	      setTimeout(() => {
