---
import type { RankingEntry } from '../../lib/dashboard-data';
import type { DimensionKey } from '../../lib/mind-score';

interface Props {
  rankings: RankingEntry[];
}

const { rankings } = Astro.props;

const DIM_COLORS: Record<DimensionKey, string> = {
  m: '#00ff88',
  i: '#00c8ff',
  n: '#7b4bff',
  d: '#ffb400',
};

const DIM_NAMES: Record<DimensionKey, string> = {
  m: 'Material',
  i: 'Intelligence',
  n: 'Network',
  d: 'Diversity',
};

function formatScore(val: number | null): string {
  if (val === null) return '--';
  return String(Math.round(val));
}
---

<div id="ranking-table" class="overflow-x-auto rounded-lg border border-white/10">
  <table class="w-full text-sm border-collapse" aria-label="Top countries by MIND score">
    <caption class="px-4 py-3 text-left text-lg font-semibold font-display text-text">
      Top {rankings.length} Countries by MIND Score
    </caption>
    <thead>
      <tr class="border-b border-white/10 bg-surface-2 text-text-muted text-xs uppercase tracking-wider">
        <th class="px-3 py-2 text-left font-medium">#</th>
        <th class="px-3 py-2 text-left font-medium">Country</th>
        <th class="px-3 py-2 text-right font-medium">MIND</th>
        <th class="px-3 py-2 text-right font-medium" style="color: #00ff88">M</th>
        <th class="px-3 py-2 text-right font-medium" style="color: #00c8ff">I</th>
        <th class="px-3 py-2 text-right font-medium" style="color: #7b4bff">N</th>
        <th class="px-3 py-2 text-right font-medium" style="color: #ffb400">D</th>
        <th class="px-3 py-2 text-left font-medium">Binding Constraint</th>
      </tr>
    </thead>
    <tbody>
      {rankings.map((country, idx) => {
        const bcKey = country.bc as DimensionKey;
        const bcColor = DIM_COLORS[bcKey] || '#8888aa';
        const bcName = DIM_NAMES[bcKey] || country.bc;
        return (
          <tr class:list={[
            "border-b border-white/5 transition-colors hover:bg-white/5",
            idx % 2 === 0 ? "bg-surface" : "bg-surface-2"
          ]}>
            <td class="px-3 py-2 text-text-muted tabular-nums">{country.rank}</td>
            <td class="px-3 py-2 text-text font-medium">{country.name}</td>
            <td class="px-3 py-2 text-right font-bold text-white tabular-nums">
              {formatScore(country.mind)}
            </td>
            <td class="px-3 py-2 text-right tabular-nums" style="color: #00ff88">
              {formatScore(country.m)}
            </td>
            <td class="px-3 py-2 text-right tabular-nums" style="color: #00c8ff">
              {formatScore(country.i)}
            </td>
            <td class="px-3 py-2 text-right tabular-nums" style="color: #7b4bff">
              {formatScore(country.n)}
            </td>
            <td class="px-3 py-2 text-right tabular-nums" style="color: #ffb400">
              {formatScore(country.d)}
            </td>
            <td class="px-3 py-2" style={`color: ${bcColor}`}>
              {bcName}
            </td>
          </tr>
        );
      })}
    </tbody>
  </table>
</div>

---
import type { DimensionKey } from '../../lib/mind-score';
import type { MethodologyIndicator } from '../../lib/dashboard-data';

interface Props {
  indicators: Record<DimensionKey, MethodologyIndicator[]>;
}

const { indicators } = Astro.props;

const DIM_COLORS: Record<DimensionKey, string> = {
  m: '#00ff88',
  i: '#00c8ff',
  n: '#7b4bff',
  d: '#ffb400',
};

const DIM_NAMES: Record<DimensionKey, string> = {
  m: 'Material',
  i: 'Intelligence',
  n: 'Network',
  d: 'Diversity',
};

const dimensions: DimensionKey[] = ['m', 'i', 'n', 'd'];
---

<div class="rounded-lg bg-surface p-6">
  <h2 class="text-xl font-semibold font-display text-text mb-2">Methodology</h2>
  <p class="text-sm text-text-muted mb-6">
    Which World Bank indicators feed each MIND dimension
  </p>

  <div class="space-y-3">
    {dimensions.map((dim) => {
      const color = DIM_COLORS[dim];
      const name = DIM_NAMES[dim];
      const items = indicators[dim] || [];
      return (
        <details class="group rounded-md bg-surface-2 border border-white/5" style={`border-left: 4px solid ${color}`}>
          <summary class="flex items-center gap-3 px-4 py-3 cursor-pointer select-none text-text hover:bg-white/5 transition-colors">
            <span class="inline-block w-2.5 h-2.5 rounded-full flex-shrink-0" style={`background-color: ${color}`} />
            <span class="font-medium">{name}</span>
            <span class="text-text-muted text-sm">({items.length} indicators)</span>
            <svg class="ml-auto w-4 h-4 text-text-muted transition-transform group-open:rotate-90" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M9 5l7 7-7 7" />
            </svg>
          </summary>
          <ul class="px-4 pb-4 pt-1 space-y-2">
            {items.map((ind) => (
              <li class="flex flex-col gap-0.5 sm:flex-row sm:items-baseline sm:gap-3 text-sm">
                <code class="text-xs font-mono text-text-muted bg-bg px-1.5 py-0.5 rounded whitespace-nowrap">
                  {ind.code}
                </code>
                <span class="text-text">{ind.name}</span>
              </li>
            ))}
          </ul>
        </details>
      );
    })}
  </div>
</div>

