1	/**
2	 * Dashboard island initialization script.
3	 *
4	 * Uses TWO separate loading paths (not a single island wrapper):
5	 * - ECharts: IntersectionObserver on #dashboard-data (client:visible semantics)
6	 * - Search: requestIdleCallback (client:idle semantics)
7	 *
8	 * Both paths share the same state store for coordinated updates.
9	 * No top-level static imports of heavy modules (echarts, charts, search).
10	 */
11	
12	// Eagerly import state (tiny, no heavy deps)
13	import { createDashboardState, type Scale } from './state';
14	import { decodeDashboardURL, pushDashboardURL } from './url-state';
15	import type { SlimCountry } from './search';
16	import type { DimensionKey } from '../../lib/mind-score';
